USE bishe;

-- =========================================================
-- 真实热门单机游戏数据插入（原始样本100款，执行时会剔除与12号脚本重复的条目）
-- 数据来源：2024-2025年Steam畅销榜、3A大作榜单、国产单机销量榜
-- 包含：国际3A大作、国产精品、独立游戏、经典重制版
-- 依赖：请先执行 05_分类扩展与现有游戏类型补充.sql
-- =========================================================

-- 临时表：存储游戏基础数据
DROP TEMPORARY TABLE IF EXISTS tmp_real_games;
CREATE TEMPORARY TABLE tmp_real_games (
    seq_no INT PRIMARY KEY,
    game_name VARCHAR(100) NOT NULL,
    primary_category VARCHAR(50) NOT NULL,
    secondary_category VARCHAR(50) NOT NULL,
    tertiary_category VARCHAR(50) NULL,
    description TEXT NOT NULL,
    developer VARCHAR(80) NOT NULL,
    publisher VARCHAR(80) NOT NULL,
    release_date DATE NOT NULL,
    price DECIMAL(10,2) NOT NULL,
    discount_price DECIMAL(10,2) NULL,
    image_url VARCHAR(500) NOT NULL,
    requirements VARCHAR(255) NOT NULL,
    tags VARCHAR(300) NOT NULL,
    rating DECIMAL(3,2) NOT NULL,
    rating_count INT NOT NULL,
    download_count INT NOT NULL,
    is_featured BOOLEAN NOT NULL
) ENGINE=InnoDB;

-- 插入100款真实热门游戏数据
INSERT INTO tmp_real_games VALUES
-- ========== 1-10: 2024-2025年度最畅销3A大作 ==========
(1, '黑神话：悟空', '动作游戏', '角色扮演', '剧情向', '《黑神话：悟空》是由游戏科学开发的国产3A动作角色扮演游戏，以中国古典名著《西游记》为背景。玩家将扮演天命人，在充满东方神话色彩的世界中探索、战斗，体验极致的动作打击感和电影级画面表现。游戏采用虚幻引擎5开发，拥有顶级的视觉效果和深度的战斗系统。', '游戏科学', '游戏科学', '2024-08-20', 268.00, NULL, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-9700 / 16GB / RTX 2060 / 130GB', '动作,角色扮演,国产,3A,神话,剧情,硬核,虚幻5', 9.6, 850000, 28000000, TRUE),
(2, '战地6', '射击游戏', '动作游戏', '多人联机', '《战地6》是EA DICE开发的最新一代战地系列射击游戏，以现代战争为背景。游戏提供大规模多人对战、破坏环境系统和多样化的兵种装备。2025年成为美国年度最畅销游戏，首月销量突破700万份。', 'EA DICE', 'Electronic Arts', '2025-10-15', 398.00, 298.00, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-10700 / 16GB / RTX 3060 / 100GB', '射击,多人,战争,战术,竞技,3A,现代战争', 8.5, 420000, 15000000, TRUE),
(3, '艾尔登法环：黑夜君临', '动作游戏', '角色扮演', '开放世界', '《艾尔登法环：黑夜君临》是FromSoftware开发的黑暗奇幻动作RPG，为艾尔登法环系列的最新作品。游戏延续了高难度战斗和深度探索的核心玩法，加入了全新的黑夜机制和多结局剧情。2025年5月登顶Steam全球畅销榜。', 'FromSoftware', 'Bandai Namco', '2025-05-30', 398.00, NULL, 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-8700K / 16GB / RTX 3070 / 80GB', '魂系,动作,开放世界,高难度,黑暗奇幻,多人合作', 9.4, 380000, 12000000, TRUE),
(4, '怪物猎人：荒野', '动作游戏', '角色扮演', '开放世界', '《怪物猎人：荒野》是Capcom开发的最新一代怪物猎人系列作品。游戏采用开放世界设计，拥有更广阔的狩猎场、更智能的怪物AI和更丰富的武器系统。支持4人联机合作狩猎，是2025年最受期待的动作游戏之一。', 'Capcom', 'Capcom', '2025-02-28', 368.00, NULL, 'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-10400 / 16GB / RTX 3060 / 75GB', '动作,狩猎,开放世界,合作,装备收集,共斗', 9.2, 520000, 18000000, TRUE),
(5, '刺客信条：影', '动作游戏', '角色扮演', '开放世界', '《刺客信条：影》是育碧开发的刺客信条系列最新作，背景设定在日本战国时代。玩家可以扮演忍者直江和武士弥助两个角色，体验不同的战斗风格和剧情线。游戏大幅强化了潜行和跑酷系统，被玩家誉为"最刺客的刺客信条"。', 'Ubisoft', 'Ubisoft', '2025-03-20', 348.00, 298.00, 'https://images.unsplash.com/photo-1533613220915-609f661a6fe1?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-10700 / 16GB / RTX 3070 / 100GB', '动作,潜行,开放世界,历史,忍者,日本,3A', 8.8, 290000, 8500000, TRUE),
(6, '赛博朋克2077：往日之影', '角色扮演', '动作游戏', '开放世界', '《赛博朋克2077：往日之影》是CDPR推出的资料片，大幅扩展了夜之城的故事。新区域"狗镇"带来全新剧情线、载具和技能树。配合2.0版本更新，游戏在2024年强势回归，成为Steam热销榜常客。', 'CD Projekt Red', 'CD Projekt', '2023-09-26', 298.00, 149.00, 'https://images.unsplash.com/photo-1535378437327-b71494669e9d?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-12700 / 16GB / RTX 3080 / 90GB', '赛博朋克,开放世界,剧情,科幻,角色扮演,3A', 9.3, 680000, 25000000, TRUE),
(7, '博德之门3', '角色扮演', '策略游戏', '剧情向', '《博德之门3》是Larian Studios开发的CRPG神作，基于龙与地下城第五版规则。游戏拥有极高的自由度、复杂的剧情分支和深度的角色扮演系统。2023年TGA年度游戏，2024年持续热销，被誉为CRPG的复兴之作。', 'Larian Studios', 'Larian Studios', '2023-08-03', 298.00, 238.00, 'https://images.unsplash.com/photo-1519074069444-1ba4fff66d16?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-8700K / 16GB / RTX 3060 / 150GB', 'CRPG,DND,剧情,策略,回合制,角色扮演,神作', 9.8, 920000, 22000000, TRUE),
(8, '荒野大镖客：救赎2', '动作游戏', '开放世界', '剧情向', '《荒野大镖客：救赎2》是R星开发的西部题材开放世界神作。游戏以19世纪末的美国西部为背景，讲述范德林德帮派的兴衰史。极致的细节、深刻的剧情和沉浸式的世界构建，被誉为"第九艺术"的典范。', 'Rockstar Games', 'Rockstar Games', '2019-11-05', 279.00, 92.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-4770K / 12GB / RTX 2060 / 150GB', '开放世界,西部,剧情,动作,沉浸式,3A,R星', 9.7, 1200000, 55000000, TRUE),
(9, '战神：诸神黄昏', '动作游戏', '角色扮演', '剧情向', '《战神：诸神黄昏》是圣莫尼卡工作室开发的战神系列最新作。奎托斯与阿特柔斯父子在北欧神话世界中的史诗冒险迎来高潮。游戏拥有电影级的演出、流畅的战斗系统和感人的父子情故事。', 'Santa Monica Studio', 'Sony', '2022-11-09', 398.00, 199.00, 'https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500K / 8GB / GTX 960 / 70GB', '动作,神话,剧情,3A,史诗,北欧,父子情', 9.5, 450000, 15000000, TRUE),
(10, '霍格沃茨之遗', '角色扮演', '动作游戏', '开放世界', '《霍格沃茨之遗》是Avalanche Software开发的哈利波特世界观开放世界RPG。玩家可以创建自己的巫师角色，在1800年代的霍格沃茨学习魔法、探索秘密。游戏完美还原了魔法世界的细节，是2023年最畅销游戏之一。', 'Avalanche Software', 'Warner Bros', '2023-02-10', 298.00, 149.00, 'https://images.unsplash.com/photo-1547592166-23acbe3a624b?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 16GB / GTX 1070 / 85GB', '魔法,开放世界,哈利波特,角色扮演,探索,3A', 9.0, 580000, 24000000, TRUE),

-- ========== 11-20: 经典3A与重制版 ==========
(11, '最终幻想7：重生', '角色扮演', '动作游戏', '剧情向', '《最终幻想7：重生》是Square Enix开发的FF7重制三部曲第二部。游戏延续了克劳德一行人的冒险，开放世界设计更加成熟，战斗系统融合了即时动作和策略指令。2024年PS5独占发售，PC版备受期待。', 'Square Enix', 'Square Enix', '2024-02-29', 446.00, NULL, 'https://images.unsplash.com/photo-1552820728-8b83bb6b2b0a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-10700 / 16GB / RTX 3070 / 100GB', 'JRPG,动作,剧情,重制,经典,3A,最终幻想', 9.3, 320000, 8000000, TRUE),
(12, '生化危机4：重制版', '恐怖惊悚', '动作游戏', '射击游戏', '《生化危机4：重制版》是Capcom对2005年经典作品的完全重制。游戏在保留原作精髓的基础上，全面革新了画面、操作和关卡设计。里昂的西班牙营救之旅再次成为恐怖动作游戏的标杆。', 'Capcom', 'Capcom', '2023-03-24', 298.00, 149.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-7500 / 8GB / GTX 1050 Ti / 60GB', '恐怖,动作,射击,重制,生存,3A,经典', 9.7, 480000, 12000000, TRUE),
(13, '星空', '角色扮演', '开放世界', '科幻', '《星空》是Bethesda开发25年的太空题材RPG巨作。游戏拥有超过1000个可探索星球，玩家可以自由建造飞船、建立前哨站，体验太空探险的乐趣。尽管发售初期争议不断，但后续更新使其成为2024年热门游戏。', 'Bethesda', 'Bethesda', '2023-09-06', 298.00, 149.00, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-6800K / 16GB / RTX 2080 / 125GB', '太空,科幻,开放世界,RPG,探索,3A,B社', 7.8, 380000, 10000000, FALSE),
(14, '暗黑破坏神4', '角色扮演', '动作游戏', '多人联机', '《暗黑破坏神4》是暴雪经典ARPG系列的最新正统续作。游戏回归黑暗哥特风格，拥有庞大的开放世界、丰富的职业Build和深度的终局玩法。赛季制更新持续带来新内容，是刷子游戏的巅峰之作。', 'Blizzard', 'Blizzard', '2023-06-05', 488.00, 244.00, 'https://images.unsplash.com/photo-1519074069444-1ba4fff66d16?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500K / 8GB / GTX 660 / 90GB', 'ARPG,暗黑,刷装备,多人,赛季,3A,暴雪', 8.2, 520000, 18000000, TRUE),
(15, '使命召唤：黑色行动6', '射击游戏', '动作游戏', '多人联机', '《使命召唤：黑色行动6》是Treyarch开发的COD系列最新作，背景设定在1990年代初的海湾战争时期。战役模式回归经典线性设计，多人模式引入全向移动系统，僵尸模式也有全新体验。', 'Treyarch', 'Activision', '2024-10-25', 488.00, 366.00, 'https://images.unsplash.com/photo-1552820728-8b83bb6b2b0a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-6600K / 12GB / GTX 1060 / 100GB', '射击,多人,战争,动作,竞技,3A,COD', 7.5, 450000, 20000000, TRUE),
(16, '死亡搁浅2：冥滩之上', '动作游戏', '冒险', '剧情向', '《死亡搁浅2：冥滩之上》是小岛秀夫工作室的续作。山姆的新冒险将跨越墨西哥到澳大利亚，面对新的BT威胁和人类连接的挑战。游戏在环境互动、战斗系统和叙事方式上都有大幅进化。', 'Kojima Productions', 'Sony', '2025-06-26', 398.00, NULL, 'https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-10700 / 16GB / RTX 3070 / 80GB', '动作,剧情,科幻,送货,小岛秀夫,3A,独特', 9.1, 180000, 5000000, TRUE),
(17, '漫威蜘蛛侠2', '动作游戏', '开放世界', '剧情向', '《漫威蜘蛛侠2》是Insomniac Games开发的蜘蛛侠系列最新作。彼得·帕克和迈尔斯·莫拉莱斯双主角设定，毒液作为反派登场。游戏拥有更流畅的蛛丝摆荡、更激烈的战斗和更感人的剧情。', 'Insomniac Games', 'Sony', '2023-10-20', 398.00, 199.00, 'https://images.unsplash.com/photo-1635805737707-575885ab0820?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-9700K / 16GB / RTX 3060 / 75GB', '动作,开放世界,超级英雄,漫威,剧情,3A', 9.4, 340000, 10000000, TRUE),
(18, '最后生还者：第一部', '动作游戏', '冒险', '剧情向', '《最后生还者：第一部》是顽皮狗经典作品的完全重制版。乔尔和艾莉的末世之旅以全新的画面技术重现，是线性叙事游戏的巅峰之作。深刻的情感描写和紧张刺激的生存战斗令人难忘。', 'Naughty Dog', 'Sony', '2022-09-02', 398.00, 199.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-4770K / 16GB / GTX 1060 / 80GB', '动作,生存,剧情,末日,3A,叙事,经典', 9.6, 420000, 12000000, TRUE),
(19, '巫师3：狂猎', '角色扮演', '开放世界', '剧情向', '《巫师3：狂猎》是CDPR开发的开放世界RPG神作。猎魔人杰洛特的最终冒险，拥有庞大的开放世界、复杂的道德选择和令人难忘的角色。次世代更新进一步提升了画面表现，是必玩的RPG经典。', 'CD Projekt Red', 'CD Projekt', '2015-05-19', 127.00, 38.00, 'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500K / 6GB / GTX 660 / 50GB', '开放世界,剧情,奇幻,角色扮演,3A,经典,神作', 9.8, 1500000, 50000000, TRUE),
(20, '上古卷轴5：天际', '角色扮演', '开放世界', '冒险', '《上古卷轴5：天际》是Bethesda开发的开放世界RPG传奇。玩家扮演龙裔在诺德大陆冒险，对抗远古巨龙奥杜因。庞大的MOD社区让游戏生命力延续十余年，是自由度最高的RPG之一。', 'Bethesda', 'Bethesda', '2011-11-11', 128.00, 32.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-750 / 4GB / GTX 260 / 12GB', '开放世界,奇幻,角色扮演,MOD,龙,经典,B社', 9.7, 2000000, 60000000, TRUE),

-- ========== 21-30: 魂系与动作游戏 ==========
(21, '艾尔登法环', '动作游戏', '角色扮演', '开放世界', '《艾尔登法环》是FromSoftware开发的开放世界魂系游戏，2022年TGA年度游戏。游戏将魂系列的高难度战斗与广阔的开放世界完美结合，拥有丰富的Build搭配和史诗级的Boss战。', 'FromSoftware', 'Bandai Namco', '2022-02-25', 298.00, 198.00, 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 12GB / GTX 1070 / 60GB', '魂系,开放世界,高难度,动作,3A,神作,奇幻', 9.6, 780000, 25000000, TRUE),
(22, '只狼：影逝二度', '动作游戏', '冒险', '剧情向', '《只狼：影逝二度》是FromSoftware开发的忍者题材动作游戏，2019年TGA年度游戏。游戏强调精准的格挡和反击，独特的"架势"系统带来快节奏的刀剑对决。日本战国时代的黑暗奇幻故事令人沉浸。', 'FromSoftware', 'Activision', '2019-03-22', 268.00, 134.00, 'https://images.unsplash.com/photo-1514539079130-25950c84965d?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-2100 / 4GB / GTX 760 / 25GB', '动作,忍者,高难度,魂系,潜行,3A,年度游戏', 9.5, 520000, 15000000, TRUE),
(23, '黑暗之魂3', '动作游戏', '角色扮演', '冒险', '《黑暗之魂3》是FromSoftware开发的魂系列正统续作。游戏延续了系列标志性的高难度战斗和晦涩深刻的剧情，拥有系列最丰富的武器系统和最史诗的Boss战。传火之旅的终结令人难忘。', 'FromSoftware', 'Bandai Namco', '2016-03-24', 268.00, 67.00, 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-2100 / 4GB / GTX 750 Ti / 25GB', '魂系,动作,高难度,黑暗奇幻,3A,经典', 9.4, 680000, 20000000, TRUE),
(24, '血源诅咒', '动作游戏', '角色扮演', '恐怖惊悚', '《血源诅咒》是FromSoftware开发的PS独占魂系游戏。维多利亚时代的哥特恐怖风格、快节奏的攻击性战斗和克苏鲁式的恐怖氛围，使其成为许多玩家心中最好的魂系游戏。', 'FromSoftware', 'Sony', '2015-03-24', 298.00, NULL, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：PS5独占 / 需要PS Plus会员', '魂系,恐怖,动作,维多利亚,克苏鲁,3A,独占', 9.7, 380000, 8000000, TRUE),
(25, '仁王2', '动作游戏', '角色扮演', '剧情向', '《仁王2》是Team Ninja开发的动作RPG，背景设定在日本战国时代。游戏融合了魂系的高难度和刷刷刷的装备系统，独特的"妖化"系统和丰富的武器流派带来极高的可玩性。', 'Team Ninja', 'Koei Tecmo', '2020-03-12', 249.00, 62.00, 'https://images.unsplash.com/photo-1514539079130-25950c84965d?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-4460 / 6GB / GTX 1060 / 80GB', '动作,日本战国,魂系,装备,妖怪,3A', 9.0, 280000, 6000000, FALSE),
(26, '卧龙：苍天陨落', '动作游戏', '角色扮演', '剧情向', '《卧龙：苍天陨落》是Team Ninja开发的三国题材动作游戏。游戏以东汉末年为背景，玩家将扮演无名义勇兵对抗妖魔化的三国武将。独特的"化解"系统和气势机制带来流畅的战斗体验。', 'Team Ninja', 'Koei Tecmo', '2023-03-03', 298.00, 149.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 8GB / GTX 1650 / 60GB', '动作,三国,魂系,武术,剧情,3A,TeamNinja', 8.3, 220000, 5000000, FALSE),
(27, '匹诺曹的谎言', '动作游戏', '角色扮演', '剧情向', '《匹诺曹的谎言》是韩国Neowiz开发的魂系动作游戏，以黑暗童话《匹诺曹》为灵感。游戏拥有独特的武器组装系统和谎言机制，蒸汽朋克风格的克拉特城令人印象深刻。', 'Neowiz', 'Neowiz', '2023-09-19', 298.00, 149.00, 'https://images.unsplash.com/photo-1560167016-022b78a0258e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-6300 / 8GB / GTX 960 / 50GB', '魂系,动作,黑暗童话,蒸汽朋克,3A,韩国', 8.6, 180000, 4000000, FALSE),
(28, '堕落之主', '动作游戏', '角色扮演', '剧情向', '《堕落之主》是Hexworks开发的魂系动作游戏，2014年《堕落之王》的重启之作。游戏拥有独特的双世界机制，玩家可以在生者和死者两个世界间切换，解决谜题和战斗。', 'Hexworks', 'CI Games', '2023-10-13', 298.00, 149.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 12GB / GTX 1060 / 45GB', '魂系,动作,黑暗奇幻,双世界,3A,高难度', 7.5, 150000, 3500000, FALSE),
(29, '装甲核心6：境界天火', '动作游戏', '模拟', '科幻', '《装甲核心6：境界天火》是FromSoftware开发的机甲动作游戏。玩家可以自定义组装机甲，在高速度的三维空间中战斗。虽然不同于魂系列，但保留了FromSoftware标志性的高难度和深度。', 'FromSoftware', 'Bandai Namco', '2023-08-25', 298.00, 198.00, 'https://images.unsplash.com/photo-1535378437327-b71494669e9d?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 12GB / GTX 1060 / 60GB', '机甲,动作,科幻,组装,高速战斗,3A,FS社', 9.0, 240000, 6000000, FALSE),
(30, '鬼泣5', '动作游戏', '冒险', '剧情向', '《鬼泣5》是Capcom开发的鬼泣系列正统续作，时隔十年的回归。但丁、尼禄和新角色V三位主角带来截然不同的战斗风格，华丽的连击系统和顶级的动作设计使其成为ACT游戏的巅峰。', 'Capcom', 'Capcom', '2019-03-08', 198.00, 65.00, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-4460 / 8GB / GTX 760 / 35GB', '动作,华丽,连击,恶魔,3A,ACT,经典', 9.5, 450000, 12000000, TRUE),

-- ========== 31-40: 射击与战术游戏 ==========
(31, '毁灭战士：黑暗时代', '射击游戏', '动作游戏', '恐怖惊悚', '《毁灭战士：黑暗时代》是id Software开发的DOOM系列最新作，背景设定在中世纪。玩家将使用盾锯、连枷等中世纪武器对抗地狱军团，保留了系列标志性的高速战斗和暴力美学。', 'id Software', 'Bethesda', '2025-05-15', 298.00, NULL, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-10700 / 16GB / RTX 3060 / 80GB', '射击,动作,中世纪,暴力,快节奏,3A,DOOM', 8.8, 120000, 3000000, TRUE),
(32, '严阵以待', '射击游戏', '战术', '模拟', '《严阵以待》是Void Interactive开发的硬核战术射击游戏。玩家扮演SWAT队员执行各种高危任务，强调真实的战术配合、武器操作和CQB战术。游戏在Steam获得极高评价，是硬核射击玩家的最爱。', 'Void Interactive', 'Team17', '2023-12-13', 128.00, 96.00, 'https://images.unsplash.com/photo-1552820728-8b83bb6b2b0a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500K / 8GB / GTX 960 / 50GB', '射击,战术,硬核,警察,CQB,模拟,多人', 9.2, 280000, 8000000, FALSE),
(33, '逃离塔科夫', '射击游戏', '生存', '模拟', '《逃离塔科夫》是Battlestate Games开发的硬核生存射击游戏。游戏以俄罗斯虚构城市塔科夫为背景，融合了RPG和FPS元素，拥有极其复杂的武器改装系统和真实的生存机制。', 'Battlestate Games', 'Battlestate Games', '2017-07-27', 368.00, NULL, 'https://images.unsplash.com/photo-1552820728-8b83bb6b2b0a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500 / 8GB / GTX 1060 / 35GB', '射击,生存,硬核,战术,装备,多人,俄罗斯', 8.5, 350000, 10000000, FALSE),
(34, '绝地潜兵2', '射击游戏', '动作游戏', '多人联机', '《绝地潜兵2》是Arrowhead Studios开发的合作射击游戏，是2015年《绝地潜兵》的续作。玩家扮演超级地球的精英士兵，对抗虫族和机器人军团。游戏强调友军伤害和战术配合，2024年成为现象级爆款。', 'Arrowhead Studios', 'Sony', '2024-02-08', 198.00, 138.00, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-9700K / 16GB / RTX 2060 / 100GB', '射击,合作,科幻,多人,战术,3A,爆款', 8.0, 520000, 12000000, TRUE),
(35, '泰坦陨落2', '射击游戏', '动作游戏', '科幻', '《泰坦陨落2》是Respawn Entertainment开发的科幻射击神作。玩家扮演铁驭驾驶泰坦机甲，拥有FPS史上最优秀的单人战役之一。虽然发售时销量不佳，但凭借口碑成为经典，现在拥有庞大的忠实玩家群。', 'Respawn Entertainment', 'EA', '2016-10-28', 158.00, 25.00, 'https://images.unsplash.com/photo-1535378437327-b71494669e9d?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-6300t / 8GB / GTX 660 / 45GB', '射击,机甲,科幻,剧情,多人,3A,神作', 9.6, 480000, 15000000, TRUE),
(36, '无主之地3', '射击游戏', '角色扮演', '多人联机', '《无主之地3》是Gearbox开发的刷宝射击游戏。游戏拥有数十亿把随机生成的武器、四个独特的猎人职业和荒诞幽默的剧情。合作模式支持四人联机，是和朋友一起刷装备的最佳选择。', 'Gearbox Software', '2K Games', '2019-09-13', 199.00, 29.00, 'https://images.unsplash.com/photo-1552820728-8b83bb6b2b0a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-3570 / 6GB / GTX 680 / 75GB', '射击,刷宝,RPG,合作,幽默,3A,多人', 8.8, 420000, 15000000, FALSE),
(37, '彩虹六号：围攻', '射击游戏', '战术', '多人联机', '《彩虹六号：围攻》是育碧开发的硬核战术射击游戏。游戏强调环境破坏、战术配合和干员技能搭配，拥有庞大的电竞赛事和持续的内容更新，是运营最成功的多人射击游戏之一。', 'Ubisoft', 'Ubisoft', '2015-12-01', 88.00, 22.00, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-560 / 6GB / GTX 460 / 61GB', '射击,战术,电竞,多人,硬核,3A,运营', 8.7, 680000, 80000000, FALSE),
(38, 'CS2', '射击游戏', '竞技', '多人联机', '《反恐精英2》是Valve开发的经典竞技射击游戏CS:GO的续作。采用全新Source 2引擎，改进的烟雾系统和Sub-tick技术带来更精准的射击体验。作为全球玩家最多的竞技FPS，拥有庞大的电竞生态。', 'Valve', 'Valve', '2023-09-27', 0.00, NULL, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-750 / 8GB / GTX 1050 / 85GB', '射击,竞技,电竞,多人,硬核,免费,V社', 8.5, 1200000, 40000000, FALSE),
(39, 'Apex英雄', '射击游戏', '大逃杀', '多人联机', '《Apex英雄》是Respawn开发的大逃杀射击游戏，设定在泰坦陨落宇宙。游戏拥有独特的英雄技能系统、流畅的移动机制和快节奏的战斗。免费游玩模式使其成为Steam上最受欢迎的大逃杀游戏之一。', 'Respawn Entertainment', 'EA', '2019-02-04', 0.00, NULL, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-6300 / 6GB / GT 640 / 56GB', '射击,大逃杀,英雄技能,多人,免费,竞技', 8.6, 890000, 25000000, FALSE),
(40, '瓦罗兰特', '射击游戏', '战术', '多人联机', '《瓦罗兰特》是拳头游戏开发的5v5战术射击游戏。游戏融合了CS:GO的精准射击和英雄技能，强调团队配合和战术执行。全球电竞赛事火热，是近年来最成功的竞技射击新IP。', 'Riot Games', 'Riot Games', '2020-06-02', 0.00, NULL, 'https://images.unsplash.com/photo-1542751110-97427bbecf20?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-4150 / 4GB / GT 730 / 26GB', '射击,战术,电竞,英雄技能,多人,免费,拳头', 8.3, 750000, 20000000, FALSE),

-- ========== 41-50: 策略与模拟游戏 ==========
(41, '文明6', '策略游戏', '回合策略', '模拟', '《文明6》是Firaxis开发的回合制策略游戏经典。玩家领导一个文明从石器时代发展到信息时代，通过科技、文化、宗教或军事手段取得胜利。丰富的文明领袖和迭起兴衰资料片带来极高的重玩价值。', 'Firaxis Games', '2K Games', '2016-10-21', 199.00, 19.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2300 / 4GB / GTX 770 / 15GB', '策略,回合制,历史,文明,4X,经典,再来一回合', 9.3, 520000, 15000000, TRUE),
(42, '全面战争：三国', '策略游戏', '回合策略', '动作游戏', '《全面战争：三国》是Creative Assembly开发的三国题材策略游戏。游戏结合了回合制战略和即时战术战斗，完美还原了三国时期的英雄豪杰和史诗战役。独特的英雄系统和关系机制令人印象深刻。', 'Creative Assembly', 'SEGA', '2019-05-23', 268.00, 67.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-8700K / 6GB / GTX 970 / 40GB', '策略,三国,即时战术,回合制,3A,历史', 8.9, 280000, 8000000, FALSE),
(43, '全面战争：战锤3', '策略游戏', '回合策略', '奇幻', '《全面战争：战锤3》是Creative Assembly开发的奇幻策略游戏，战锤三部曲的终章。游戏拥有四个混沌魔域和震旦天朝等全新派系，宏大的战役地图和史诗的恶魔亲王自定义系统带来极致的策略体验。', 'Creative Assembly', 'SEGA', '2022-02-17', 298.00, 149.00, 'https://images.unsplash.com/photo-1519074069444-1ba4fff66d16?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-8100 / 5GB / GTX 900 / 70GB', '策略,战锤,奇幻,即时战术,回合制,3A', 8.7, 180000, 5000000, FALSE),
(44, '十字军之王3', '策略游戏', '模拟', '角色扮演', '《十字军之王3》是Paradox开发的中世纪大战略游戏。玩家扮演中世纪贵族家族，通过外交、阴谋、战争等手段扩张势力。深度的角色扮演系统和复杂的中世纪政治模拟令人沉迷。', 'Paradox Development', 'Paradox Interactive', '2020-09-01', 218.00, 87.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-4670K / 6GB / GTX 1650 / 8GB', '策略,中世纪,大战略,角色扮演,模拟,P社', 9.4, 220000, 6000000, TRUE),
(45, '欧陆风云4', '策略游戏', '大战略', '模拟', '《欧陆风云4》是Paradox开发的近代早期大战略游戏。玩家扮演1444年至1821年间的国家，通过探索、贸易、战争和外交塑造历史。庞大的DLC体系和深度历史模拟使其成为历史策略游戏的标杆。', 'Paradox Development', 'Paradox Interactive', '2013-08-13', 112.00, 28.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / Core2Duo / 2GB / GTX 260 / 6GB', '策略,大战略,历史,近代,模拟,P社,经典', 9.2, 280000, 8000000, FALSE),
(46, '城市：天际线2', '模拟经营', '策略游戏', '沙盒创造', '《城市：天际线2》是Colossal Order开发的城市建设模拟游戏续作。游戏大幅改进了经济系统和市民AI，拥有更真实的交通模拟和更细致的城市管理。是城市规划爱好者的终极沙盒。', 'Colossal Order', 'Paradox Interactive', '2023-10-24', 218.00, 109.00, 'https://images.unsplash.com/photo-1480714378408-67cf0d13bc1b?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-9700K / 16GB / RTX 3080 / 60GB', '模拟,城市建设,策略,沙盒,经营,交通,3A', 7.8, 150000, 4000000, FALSE),
(47, '模拟人生4', '模拟经营', '生活模拟', '沙盒创造', '《模拟人生4》是Maxis开发的生活模拟游戏。玩家创建虚拟人物，控制他们的日常生活、职业发展、人际关系。丰富的扩展包和MOD支持让游戏拥有无限可能，是史上最畅销的模拟游戏之一。', 'Maxis', 'EA', '2014-09-02', 0.00, NULL, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-3220 / 4GB / GTX 650 / 26GB', '模拟,生活,沙盒,创造,免费,MOD,经典', 8.0, 680000, 50000000, FALSE),
(48, '星露谷物语', '模拟经营', '角色扮演', '休闲游戏', '《星露谷物语》是ConcernedApe独立开发的农场模拟游戏。玩家继承爷爷的农场，种植作物、饲养动物、结交朋友、探索矿洞。温馨的像素风格和丰富的内容使其成为独立游戏的神作。', 'ConcernedApe', 'ConcernedApe', '2016-02-26', 48.00, 28.00, 'https://images.unsplash.com/photo-1500937386664-56d1dfef3854?w=800&h=450&fit=crop', '推荐配置：Win10 / 2GB内存 / 256MB显存 / 500MB', '模拟,农场,像素,独立,休闲,RPG,神作', 9.8, 850000, 30000000, TRUE),
(49, '戴森球计划', '模拟经营', '策略游戏', '科幻', '《戴森球计划》是柚子猫工作室开发的科幻模拟经营游戏。玩家建造自动化工厂，最终目标是建造包裹恒星的戴森球。复杂的物流系统和优美的宇宙景观，是国产独立游戏的杰出代表。', '柚子猫工作室', 'Gamera Games', '2021-01-21', 70.00, 56.00, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Win10 / i3-530 / 4GB / GTX 750 Ti / 3GB', '模拟,自动化,科幻,国产,独立,策略,建造', 9.6, 320000, 8000000, TRUE),
(50, '异星工厂', '模拟经营', '策略游戏', '沙盒创造', '《异星工厂》是Wube Software开发的自动化建造游戏。玩家在异星建造工厂，研究科技，抵御虫族攻击。极其深度的生产线优化和逻辑电路系统，被玩家誉为"电子海洛因"。', 'Wube Software', 'Wube Software', '2020-08-14', 90.00, 60.00, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Win10 / i3-3210 / 4GB / GTX 260 / 4GB', '模拟,自动化,策略,建造,沙盒,独立,经典', 9.7, 280000, 7000000, TRUE),

-- ========== 51-60: 恐怖与生存游戏 ==========
(51, '生化危机8：村庄', '恐怖惊悚', '动作游戏', '射击游戏', '《生化危机8：村庄》是Capcom开发的生化危机系列最新作。伊森·温特斯的续篇故事，融合了生化7的恐怖和生化4的动作元素。巨大的吸血鬼夫人迪米特雷斯库成为游戏标志，是2021年最畅销游戏之一。', 'Capcom', 'Capcom', '2021-05-07', 298.00, 99.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-7500 / 8GB / GTX 1050 Ti / 35GB', '恐怖,动作,射击,吸血鬼,3A,生化危机,生存', 9.0, 380000, 10000000, TRUE),
(52, '逃生2', '恐怖惊悚', '冒险', '剧情向', '《逃生2》是Red Barrels开发的第一人称恐怖游戏续作。玩家扮演记者布莱克·兰格曼，在亚利桑那州的邪教村落调查孕妇谋杀案。游戏延续了前作的摄像机夜视机制和心理恐怖氛围。', 'Red Barrels', 'Red Barrels', '2017-04-25', 88.00, 22.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i3-530 / 4GB / GTX 260 / 30GB', '恐怖,生存,第一人称,心理恐怖,独立,剧情', 8.5, 280000, 8000000, FALSE),
(53, '恐鬼症', '恐怖惊悚', '多人联机', '模拟', '《恐鬼症》是Kinetic Games开发的合作恐怖游戏。玩家组成捉鬼小队，使用各种设备调查闹鬼地点，识别鬼魂类型。简单的玩法和极佳的直播效果使其成为2020年现象级独立游戏。', 'Kinetic Games', 'Kinetic Games', '2020-09-18', 76.00, 50.00, 'https://images.unsplash.com/photo-1509248961158-e54f6934749c?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-4590 / 8GB / GTX 970 / 16GB', '恐怖,合作,多人,捉鬼,独立,VR支持,直播', 9.1, 420000, 20000000, FALSE),
(54, '森林之子', '恐怖惊悚', '生存', '开放世界', '《森林之子》是Endnight Games开发的生存恐怖游戏续作。玩家被困在充满变异食人族的孤岛上，需要建造基地、制作武器、探索洞穴。相比前作拥有更大的地图、更智能的AI和更丰富的建造系统。', 'Endnight Games', 'Newnight', '2023-02-23', 108.00, 75.00, 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 12GB / GTX 1060 / 20GB', '恐怖,生存,建造,开放世界,合作,独立,森林', 8.7, 380000, 12000000, FALSE),
(55, '绿色地狱', '生存', '模拟', '冒险', '《绿色地狱》是Creepy Jar开发的亚马逊雨林生存游戏。玩家需要在危险的雨林环境中寻找食物、治疗疾病、建造庇护所。真实的生存机制和独特的身体检查系统带来硬核的生存体验。', 'Creepy Jar', 'Creepy Jar', '2019-09-05', 80.00, 32.00, 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&h=450&fit=crop', '推荐配置：Win10 / i3-4170 / 8GB / GTX 760 / 8GB', '生存,模拟,雨林,硬核,建造,合作,独立', 8.8, 220000, 6000000, FALSE),
(56, '漫漫长夜', '生存', '冒险', '剧情向', '《漫漫长夜》是Hinterland Studios开发的极地生存游戏。玩家在加拿大北部荒野面对严寒和野生动物，探索废弃设施，揭开神秘大停电的真相。独特的画风和叙事风格带来沉浸式的孤独体验。', 'Hinterland Studios', 'Hinterland Studios', '2017-08-01', 108.00, 32.00, 'https://images.unsplash.com/photo-1517299321609-52687d1bc55a?w=800&h=450&fit=crop', '推荐配置：Win10 / i5-2400 / 4GB / GTX 660 / 7GB', '生存,冒险,极地,剧情,探索,独立,氛围', 9.0, 180000, 5000000, FALSE),
(57, '腐蚀', '生存', '多人联机', '沙盒创造', '《腐蚀》是Facepunch Studios开发的多人生存游戏。玩家在一个充满敌意的世界中收集资源、建造基地、与其他玩家竞争或合作。残酷的自由PVP机制和深度的建造系统使其成为生存游戏的常青树。', 'Facepunch Studios', 'Facepunch Studios', '2018-02-08', 136.00, 68.00, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-4790K / 10GB / GTX 980 / 20GB', '生存,多人,PVP,建造,沙盒,硬核,长期运营', 8.3, 520000, 25000000, FALSE),
(58, '方舟：生存进化', '生存', '多人联机', '恐龙', '《方舟：生存进化》是Studio Wildcard开发的恐龙题材生存游戏。玩家在一个充满恐龙和远古生物的岛屿上生存、驯服生物、建造部落。独特的驯服系统和庞大的生物图鉴带来独特的生存体验。', 'Studio Wildcard', 'Studio Wildcard', '2017-08-29', 90.00, 22.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2400 / 8GB / GTX 670 / 60GB', '生存,恐龙,多人,驯服,建造,开放世界,3A', 8.0, 380000, 20000000, FALSE),
(59, '饥荒', '生存', '冒险', 'Roguelike肉鸽', '《饥荒》是Klei Entertainment开发的生存冒险游戏。玩家扮演被传送到异世界的科学家威尔逊，需要收集资源、对抗怪物、维持理智。独特的哥特画风和Roguelike机制带来极高的重玩价值。', 'Klei Entertainment', 'Klei Entertainment', '2013-04-23', 24.00, 6.00, 'https://images.unsplash.com/photo-1500937386664-56d1dfef3854?w=800&h=450&fit=crop', '推荐配置：Win10 / 1GB内存 / 256MB显存 / 500MB', '生存,冒险,独立,手绘,Roguelike,经典,Klei', 9.5, 580000, 25000000, TRUE),
(60, '缺氧', '模拟经营', '生存', '策略游戏', '《缺氧》是Klei Entertainment开发的太空殖民地模拟游戏。玩家管理一群复制人，在地下小行星建立基地，维持氧气、食物和能源供应。复杂的物理和化学模拟系统极具深度。', 'Klei Entertainment', 'Klei Entertainment', '2019-07-30', 58.00, 23.00, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Win10 / 2GB内存 / Intel HD 4600 / 2GB', '模拟,生存,太空,策略,物理,独立,Klei', 9.6, 320000, 10000000, TRUE),

-- ========== 61-70: 国产精品游戏 ==========
(61, '饿殍：明末千里行', '角色扮演', '剧情向', '冒险', '《饿殍：明末千里行》是零创游戏开发的明末题材AVG游戏。玩家扮演盗匪良，运送四名女孩从华州城至洛阳城，途中需查明真相并做出选择。游戏以98万销量成为2024年国产单机销量亚军。', '零创游戏', '零创游戏', '2024-04-23', 30.00, 24.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 / i3 / 4GB / 核显 / 2GB', '剧情,AVG,国产,明末,历史,文字,独立', 9.2, 180000, 980000, FALSE),
(62, '山河旅探', '解谜探索', '剧情向', '冒险', '《山河旅探》是奥秘之家开发的清末民初侦探推理游戏。玩家扮演侦探沈仲平，调查一系列离奇案件。游戏融合了中国传统侦探文化和近代科学推理，获得2024TapTap最佳叙事和最佳独立游戏奖。', '奥秘之家', '奥秘之家', '2024-01-31', 58.00, 46.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 / i3 / 4GB / GTX 750 / 4GB', '解谜,推理,国产,清末,剧情,独立,侦探', 9.4, 120000, 550000, FALSE),
(63, '灵魂面甲', '生存', '动作游戏', '多人联机', '《灵魂面甲》是营火工作室开发的SOC游戏，灵犀互娱发行。游戏以原始部落为背景，玩家需要生存、建造、战斗，并招募族人建立部落。上线首月登顶Steam全球热销榜，是出海成功的国产单机代表。', '营火工作室', 'Qooland Games', '2024-05-01', 108.00, 86.00, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 16GB / GTX 1060 / 30GB', '生存,动作,建造,国产,多人,部落,开放世界', 8.5, 95000, 550000, FALSE),
(64, '中国式网游', '模拟经营', '角色扮演', '休闲游戏', '《中国式网游》是WiseGame发行的独立游戏，以国产网游为原型，缝合了"氪金"、"战力榜"、"自动寻路"等刻板印象，达到喜剧和讽刺效果。游戏以51万销量位列2024年国产单机第五。', 'WiseGame', 'WiseGame', '2024-07-19', 32.00, 25.00, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800&h=450&fit=crop', '推荐配置：Win10 / i3 / 4GB / 核显 / 2GB', '模拟,经营,国产,网游,讽刺,独立,休闲', 8.8, 150000, 510000, FALSE),
(65, '来自星尘', '角色扮演', '策略游戏', '剧情向', '《来自星尘》是鹰角网络开发的首款买断制游戏，采用回合制战斗系统。玩家扮演调查员，探索异星文明。尽管是纯手游，但累计销量估计超过100万套，是鹰角试水买断制的成功尝试。', '鹰角网络', '鹰角网络', '2024-02-27', 68.00, NULL, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Android 8.0 / iOS 12 / 4GB RAM / 8GB', 'RPG,回合制,国产,科幻,鹰角,手游,剧情', 7.8, 200000, 1000000, FALSE),
(66, '古剑奇谭3', '角色扮演', '动作游戏', '剧情向', '《古剑奇谭3》是烛龙开发的国产RPG，古剑系列第三部正传。游戏采用即时战斗系统，以中国古代神话为背景，讲述了人族传承的故事。被誉为国产单机RPG的里程碑之作。', '上海烛龙', '网元圣唐', '2018-11-23', 99.00, 39.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win7 64位 / i5-4590 / 8GB / GTX 750 Ti / 40GB', 'RPG,国产,动作,神话,剧情,即时战斗,经典', 9.1, 280000, 2000000, TRUE),
(67, '仙剑奇侠传7', '角色扮演', '动作游戏', '剧情向', '《仙剑奇侠传7》是软星开发的仙剑系列最新作，首次采用虚幻4引擎和即时战斗系统。游戏讲述了月清疏和修吾的仙侠故事，延续了系列经典的三界世界观和感人剧情。', '软星科技', '方块游戏', '2021-10-15', 128.00, 64.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i7-9700K / 16GB / RTX 2060 / 85GB', 'RPG,国产,仙侠,动作,剧情,虚幻4,经典IP', 8.0, 220000, 1500000, FALSE),
(68, '太吾绘卷', '角色扮演', '策略游戏', 'Roguelike肉鸽', '《太吾绘卷》是螺舟工作室开发的武侠模拟游戏。玩家扮演太吾氏传人，在随机生成的江湖中修炼武功、经营门派、对抗相枢。独特的武侠系统和极高的自由度使其成为2018年现象级国产独立游戏。', '螺舟工作室', '螺舟工作室', '2018-09-21', 68.00, 48.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win7 / i3 / 4GB / 核显 / 6GB', '武侠,国产,独立,策略,Roguelike,经营,神作', 9.3, 350000, 3500000, TRUE),
(69, '鬼谷八荒', '角色扮演', '模拟', 'Roguelike肉鸽', '《鬼谷八荒》是鬼谷工作室开发的修仙模拟游戏。玩家从凡人开始修炼，经历筑基、金丹、元婴等境界，探索随机生成的八荒世界。独特的修仙系统和丰富的奇遇事件，2021年Steam国产游戏销量冠军。', '鬼谷工作室', '鬼谷工作室', '2021-01-27', 68.00, 48.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win7 / i3 / 4GB / 核显 / 6GB', '修仙,国产,独立,Roguelike,沙盒,销量冠军', 8.5, 420000, 5000000, TRUE),
(70, '逸剑风云决', '角色扮演', '策略游戏', '剧情向', '《逸剑风云决》是侠萌游戏开发的像素武侠RPG。游戏采用HD-2D画风，结合回合制和即时战斗，讲述了少年宇文逸的江湖冒险。致敬经典武侠游戏，拥有丰富的支线剧情和多结局。', '侠萌游戏', '侠萌游戏', '2023-09-15', 78.00, 62.00, 'https://images.unsplash.com/photo-1542259681-d309e31ba4f9?w=800&h=450&fit=crop', '推荐配置：Win7 / i3 / 4GB / GTX 750 / 4GB', '武侠,国产,像素,回合制,剧情,独立,HD-2D', 9.0, 95000, 800000, FALSE),

-- ========== 71-80: 独立游戏精品 ==========
(71, '哈迪斯', '动作游戏', 'Roguelike肉鸽', '剧情向', '《哈迪斯》是Supergiant Games开发的Roguelike动作游戏。玩家扮演冥王之子扎格列欧斯，试图逃离冥界。流畅的战斗、精美的画风和渐进式剧情使其成为Roguelike游戏的新标杆，获得2020年TGA最佳独立游戏。', 'Supergiant Games', 'Supergiant Games', '2020-09-17', 92.00, 46.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / i3 / 8GB / GTX 650 / 15GB', 'Roguelike,动作,独立,神作,希腊神话,剧情,美术', 9.8, 520000, 12000000, TRUE),
(72, '杀戮尖塔', '卡牌构筑', 'Roguelike肉鸽', '策略游戏', '《杀戮尖塔》是Mega Crit Games开发的卡牌Roguelike游戏。玩家选择不同职业，攀爬高塔，收集卡牌和遗物构建卡组。极简的规则和极高的策略深度，是卡牌构筑游戏的教科书级作品。', 'Mega Crit Games', 'Mega Crit Games', '2019-01-23', 80.00, 27.00, 'https://images.unsplash.com/photo-1511193311914-0346f16efe90?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 1GB', '卡牌,Roguelike,独立,策略,神作,爬塔,经典', 9.7, 480000, 10000000, TRUE),
(73, '空洞骑士', '动作游戏', '冒险', '剧情向', '《空洞骑士》是Team Cherry开发的类银河战士恶魔城游戏。玩家扮演小骑士，探索庞大的地下王国圣巢。精美的手绘风格、深度的世界观和极具挑战性的战斗，是独立游戏的神作。', 'Team Cherry', 'Team Cherry', '2017-02-24', 58.00, 29.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win7 / 4GB内存 / 核显 / 9GB', '类银河战士,动作,独立,手绘,探索,神作,虫', 9.8, 680000, 15000000, TRUE),
(74, '蔚蓝', '动作游戏', '平台跳跃', '剧情向', '《蔚蓝》是Maddy Makes Games开发的平台跳跃游戏。玩家扮演玛德琳攀登塞莱斯特山，克服内心的抑郁和焦虑。精准的操作手感、感人的剧情和优秀的关卡设计，获得2018年TGA最佳独立游戏。', 'Maddy Makes Games', 'Maddy Makes Games', '2018-01-25', 68.00, 17.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 1GB', '平台跳跃,独立,困难,剧情,像素,神作,抑郁', 9.7, 380000, 8000000, TRUE),
(75, '传说之下', '角色扮演', '剧情向', '音乐节奏', '《传说之下》是Toby Fox开发的独立RPG。玩家掉入地下怪物世界，可以选择战斗或仁慈。打破第四面墙的叙事、难忘的角色和原创音乐使其成为 cult classic，影响了整整一代独立游戏。', 'Toby Fox', 'Toby Fox', '2015-09-15', 36.00, 12.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 200MB', 'RPG,独立,剧情,像素,音乐,神作,meta', 9.9, 720000, 20000000, TRUE),
(76, '以撒的结合：重生', '动作游戏', 'Roguelike肉鸽', '射击游戏', '《以撒的结合：重生》是Edmund McMillen开发的Roguelike射击游戏。玩家控制以撒，在随机生成的地下室中战斗。庞大的道具组合、黑暗的故事和极高的重玩价值，是Roguelike游戏的先驱。', 'Edmund McMillen', 'Nicalis', '2014-11-04', 68.00, 17.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 500MB', 'Roguelike,射击,独立,黑暗,道具,神作,随机', 9.6, 450000, 12000000, TRUE),
(77, '挺进地牢', '动作游戏', 'Roguelike肉鸽', '射击游戏', '《挺进地牢》是Dodge Roll Games开发的弹幕射击Roguelike游戏。玩家选择不同枪手，挺进不断变化的地牢，寻找能够改变过去的枪。流畅的弹幕战斗和丰富的武器系统极具上瘾性。', 'Dodge Roll Games', 'Devolver Digital', '2016-04-05', 58.00, 14.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 2GB', 'Roguelike,射击,弹幕,独立,像素,地牢,困难', 9.3, 320000, 8000000, FALSE),
(78, '死亡细胞', '动作游戏', 'Roguelike肉鸽', '平台跳跃', '《死亡细胞》是Motion Twin开发的Roguelike银河城游戏。玩家扮演复活的尸体，在岛屿上探索战斗。流畅的动作、丰富的武器和不断更新的内容，是Roguelike与银河城结合的典范。', 'Motion Twin', 'Motion Twin', '2018-08-07', 80.00, 40.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / GTX 460 / 500MB', 'Roguelike,动作,银河城,独立,像素,流畅,更新', 9.5, 480000, 15000000, TRUE),
(79, '陷阵之志', '策略游戏', '回合策略', 'Roguelike肉鸽', '《陷阵之志》是Subset Games开发的策略游戏。玩家控制机甲小队，抵御外星虫族入侵，保护城市建筑。极简的规则和极高的策略深度，每一回合都像解谜，是策略游戏的杰作。', 'Subset Games', 'Subset Games', '2018-02-27', 58.00, 29.00, 'https://images.unsplash.com/photo-1519074069444-1ba4fff66d16?w=800&h=450&fit=crop', '推荐配置：Win7 / 2GB内存 / 核显 / 400MB', '策略,回合制,Roguelike,机甲,独立,像素,神作', 9.6, 280000, 6000000, TRUE),
(80, 'FTL：超越光速', '策略游戏', 'Roguelike肉鸽', '模拟', '《FTL：超越光速》是Subset Games开发的太空飞船模拟游戏。玩家指挥飞船，穿越星系，逃离叛军追击。紧张的时间管理和随机事件，每一次航行都是独特的冒险，是太空Roguelike的开山之作。', 'Subset Games', 'Subset Games', '2012-09-14', 36.00, 12.00, 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=450&fit=crop', '推荐配置：Win7 / 1GB内存 / 核显 / 250MB', '策略,Roguelike,太空,模拟,独立,像素,经典', 9.4, 320000, 8000000, FALSE),

-- ========== 81-90: 体育竞速与音乐游戏 ==========
(81, '极限竞速：地平线5', '竞速驾驶', '开放世界', '多人联机', '《极限竞速：地平线5》是Playground Games开发的开放世界赛车游戏，背景设定在墨西哥。游戏拥有系列最大的地图、最丰富的车辆选择和最逼真的天气系统。是开放世界赛车游戏的巅峰之作。', 'Playground Games', 'Xbox Game Studios', '2021-11-09', 248.00, 124.00, 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8400 / 8GB / GTX 1070 / 110GB', '竞速,开放世界,赛车,墨西哥,多人,3A,微软', 9.5, 380000, 15000000, TRUE),
(82, 'F1 24', '竞速驾驶', '体育竞技', '模拟', '《F1 24》是Codemasters开发的官方F1赛车模拟游戏。游戏拥有2024赛季全部车队、车手和赛道，全新的车辆物理和生涯模式。是F1粉丝和赛车模拟爱好者的必玩之作。', 'Codemasters', 'EA Sports', '2024-05-31', 298.00, 149.00, 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-9600K / 16GB / GTX 1660 Ti / 100GB', '竞速,F1,模拟,体育,赛车,3A,官方授权', 8.2, 85000, 2000000, FALSE),
(83, '神力科莎：竞速', '竞速驾驶', '模拟', '体育竞技', '《神力科莎：竞速》是Kunos Simulazioni开发的硬核赛车模拟游戏，宝珀GT系列赛官方游戏。游戏拥有极致真实的车辆物理和激光扫描赛道，是GT赛车模拟的标杆之作。', 'Kunos Simulazioni', '505 Games', '2019-05-29', 168.00, 42.00, 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-2500K / 6GB / GTX 970 / 50GB', '竞速,模拟,GT赛车,硬核,官方,3A,物理', 9.0, 120000, 4000000, FALSE),
(84, 'NBA 2K25', '体育竞技', '模拟', '多人联机', '《NBA 2K25》是2K开发的篮球模拟游戏最新作。游戏拥有最真实的球员建模、动作捕捉和篮球物理。全新的ProPLAY技术和丰富的游戏模式，是篮球游戏的唯一选择。', 'Visual Concepts', '2K', '2024-09-06', 298.00, 149.00, 'https://images.unsplash.com/photo-1546519638-68e109498ffc?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-4430 / 8GB / GTX 770 / 150GB', '体育,篮球,NBA,模拟,多人,3A,年货', 7.5, 180000, 8000000, FALSE),
(85, 'EA Sports FC 25', '体育竞技', '模拟', '多人联机', '《EA Sports FC 25》是EA开发的足球模拟游戏，FIFA系列的继任者。游戏拥有真实的球员动作、战术系统和授权联赛。全新的HyperMotion技术和5v5 Rush模式带来全新体验。', 'EA Vancouver', 'EA Sports', '2024-09-27', 248.00, 124.00, 'https://images.unsplash.com/photo-1522778119026-d647f0565c6a?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-6600K / 8GB / GTX 1050 Ti / 100GB', '体育,足球,模拟,多人,3A,年货,EA', 7.8, 220000, 12000000, FALSE),
(86, '美国职棒大联盟24', '体育竞技', '模拟', '剧情向', '《美国职棒大联盟24》是Sony San Diego开发的棒球模拟游戏。游戏拥有最真实的棒球物理、球员数据和球场还原。故事模式"Road to the Show"让玩家从菜鸟成长为巨星。', 'Sony San Diego', 'Sony', '2024-03-19', 398.00, 199.00, 'https://images.unsplash.com/photo-1544298621-6e7a3f47e4a9?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8600K / 8GB / GTX 960 / 80GB', '体育,棒球,MLB,模拟,剧情,3A,Sony', 8.5, 95000, 3000000, FALSE),
(87, 'GT赛车7', '竞速驾驶', '模拟', '体育竞技', '《GT赛车7》是Polyphony Digital开发的赛车模拟游戏，GT系列25周年纪念作。游戏回归经典模式，拥有最丰富的车辆调校和驾驶学院。是PlayStation平台最硬核的赛车游戏。', 'Polyphony Digital', 'Sony', '2022-03-04', 398.00, 199.00, 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=800&h=450&fit=crop', '推荐配置：Win10 64位 / i5-8600K / 16GB / GTX 1050 Ti / 110GB', '竞速,模拟,GT,硬核,车辆收集,3A,PlayStation', 8.8, 180000, 6000000, TRUE),
(88, '节奏光剑', '音乐节奏', '动作游戏', 'VR', '《节奏光剑》是Beat Games开发的VR音乐节奏游戏。玩家使用光剑切割飞来的方块，跟随音乐节奏。极佳的VR体验和丰富的曲库，是VR平台的杀手级应用和最受欢迎VR游戏。', 'Beat Games', 'Beat Games', '2019-05-21', 90.00, 58.00, 'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=800&h=450&fit=crop', '推荐配置：Win10 / i5-4590 / 8GB / GTX 970 / 2GB', '音乐,节奏,VR,光剑,运动,独立,杀手级应用', 9.6, 420000, 10000000, TRUE),
(89, 'DJMAX RESPECT V', '音乐节奏', '街机', '休闲游戏', '《DJMAX RESPECT V》是NEOWIZ开发的经典音游DJMAX的PC版。游戏拥有丰富的曲库、多种难度和模式，支持键盘和控制器操作。是PC平台最硬核的音乐游戏之一。', 'NEOWIZ', 'NEOWIZ', '2020-03-12', 138.00, 69.00, 'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=800&h=450&fit=crop', '推荐配置：Win7 / i3 / 4GB / 核显 / 10GB', '音乐,节奏,街机,硬核,下落式,韩国,经典', 9.2, 95000, 2500000, FALSE),
(90, '冰与火之歌', '音乐节奏', '平台跳跃', '休闲游戏', '《冰与火之歌》是7th Beat Games开发的节奏平台游戏。玩家控制双球跟随音乐节奏在轨道上移动，一键操作但难度极高。极简的设计和精准的节奏感，是独立音游的杰作。', '7th Beat Games', '7th Beat Games', '2018-02-25', 22.00, 11.00, 'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=800&h=450&fit=crop', '推荐配置：Win7 / 1GB内存 / 核显 / 500MB', '音乐,节奏,平台,困难,独立,极简,一键', 9.5, 180000, 5000000, TRUE),

-- ========== 91-100: 解谜与休闲游戏 ==========
(91, '传送门2', '解谜探索', '剧情向', '多人联机', '《传送门2》是Valve开发的解谜游戏神作。玩家使用传送门枪在测试室中解谜，同时体验黑色幽默的剧情。单人模式和合作模式都拥有顶级的关卡设计，被誉为史上最完美的游戏之一。', 'Valve', 'Valve', '2011-04-19', 42.00, 4.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 3GB内存 / 核显 / 8GB', '解谜,传送门,剧情,合作,V社,神作,经典', 9.9, 850000, 30000000, TRUE),
(92, '见证者', '解谜探索', '冒险', '剧情向', '《见证者》是Thekla Inc开发的开放世界解谜游戏。玩家在一个充满谜题的神秘岛屿上探索，通过画线解谜逐渐揭开真相。游戏没有文字教学，完全通过环境引导玩家，是解谜设计的教科书。', 'Thekla Inc', 'Thekla Inc', '2016-01-26', 112.00, 28.00, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=800&h=450&fit=crop', '推荐配置：Win7 / 4GB内存 / GTX 780 / 5GB', '解谜,开放世界,探索,哲学,独立,环境叙事', 9.4, 180000, 4000000, TRUE),
(93, ' Baba是你', '解谜探索', '休闲游戏', '独立', '《Baba是你》是Hempuli Oy开发的推箱子解谜游戏。玩家通过推动规则方块改变游戏逻辑，"Baba是你"、"墙是停"等规则可以被改写。极简的画面和颠覆性的玩法，是近年来最具创意的解谜游戏。', 'Hempuli Oy', 'Hempuli Oy', '2019-03-13', 58.00, 29.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 1GB内存 / 核显 / 200MB', '解谜,推箱子,逻辑,独立,像素,创意,困难', 9.6, 220000, 6000000, TRUE),
(94, '俄罗斯方块效应：连接', '休闲游戏', '音乐节奏', '多人联机', '《俄罗斯方块效应：连接》是Enhance开发的俄罗斯方块进化版。游戏在经典玩法基础上加入华丽的视觉效果和音乐同步，支持多人对战和合作模式。是史上最完美的俄罗斯方块游戏。', 'Enhance', 'Enhance', '2021-08-18', 118.00, 59.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 4GB内存 / 核显 / 2GB', '休闲,俄罗斯方块,音乐,多人,独立,经典,完美', 9.5, 95000, 3000000, FALSE),
(95, '胡闹厨房2', '休闲游戏', '派对欢乐', '多人联机', '《胡闹厨房2》是Ghost Town Games开发的合作烹饪游戏。玩家组成厨师团队，在混乱的厨房中准备菜品。简单的操作和极高的配合要求，是"分手厨房"和派对游戏的首选。', 'Ghost Town Games', 'Team17', '2018-08-07', 98.00, 24.00, 'https://images.unsplash.com/photo-1556910103-1c02745a30bf?w=800&h=450&fit=crop', '推荐配置：Win7 / 4GB内存 / 核显 / 3GB', '休闲,合作,烹饪,派对,多人,独立,欢乐', 9.0, 380000, 12000000, TRUE),
(96, '双人成行', '动作游戏', '冒险', '多人联机', '《双人成行》是Hazelight Studios开发的双人合作冒险游戏。一对即将离婚的夫妻被变成玩偶，必须合作冒险修复关系。创新的合作机制和感人的故事，获得2021年TGA年度游戏。', 'Hazelight Studios', 'EA', '2021-03-26', 198.00, 59.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win8 / 8GB内存 / GTX 660 / 50GB', '合作,双人,冒险,剧情,创新,3A,年度游戏', 9.8, 520000, 20000000, TRUE),
(97, '人类一败涂地', '休闲游戏', '解谜探索', '多人联机', '《人类一败涂地》是No Brakes Games开发的物理模拟解谜游戏。玩家控制软绵绵的角色，在梦境中解谜。滑稽的物理效果和开放的解法，配合多人模式带来无尽的欢乐。', 'No Brakes Games', 'Curve Digital', '2016-07-22', 58.00, 17.00, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win7 / 4GB内存 / GTX 460 / 2GB', '物理,解谜,多人,休闲,搞笑,独立,软体', 9.1, 680000, 25000000, TRUE),
(98, '糖豆人：终极淘汰赛', '休闲游戏', '派对欢乐', '多人联机', '《糖豆人：终极淘汰赛》是Mediatonic开发的派对大逃杀游戏。60名玩家控制糖豆人，在各种综艺关卡中竞争，最后一人获胜。可爱的画风和简单的操作，2020年现象级爆款，现已转为免费游戏。', 'Mediatonic', 'Epic Games', '2020-08-04', 0.00, NULL, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=450&fit=crop', '推荐配置：Win10 / 8GB内存 / GTX 660 / 2GB', '休闲,派对,大逃杀,多人,免费,糖豆人,综艺', 8.5, 850000, 50000000, FALSE),
(99, '潜水员戴夫', '模拟经营', '冒险', '休闲游戏', '《潜水员戴夫》是MINTROCKET开发的海洋冒险经营游戏。白天潜水捕捉鱼类，晚上经营寿司店。融合了探索、经营和轻度Roguelike，像素画风和丰富的内容使其成为2023年黑马独立游戏。', 'MINTROCKET', 'MINTROCKET', '2023-06-28', 80.00, 60.00, 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&h=450&fit=crop', '推荐配置：Win7 / 8GB内存 / GTX 750 / 10GB', '模拟,经营,潜水,海洋,独立,像素,黑马', 9.4, 280000, 8000000, TRUE),
