-- =========================================================
-- 分类名称归一：与当前 categories 表保持一致
-- 说明：
-- 1. 项目现有分类使用“生存建造”，这里把样本中的“生存”统一映射过去
-- 2. 这样可以避免主分类匹配失败，导致整条游戏数据无法插入
-- =========================================================
UPDATE tmp_real_games
SET primary_category = '生存建造'
WHERE primary_category = '生存';

UPDATE tmp_real_games
SET secondary_category = '生存建造'
WHERE secondary_category = '生存';

UPDATE tmp_real_games
SET tertiary_category = '生存建造'
WHERE tertiary_category = '生存';

-- =========================================================
-- 插入games表
-- =========================================================

-- 创建分类映射临时表
DROP TEMPORARY TABLE IF EXISTS tmp_real_category_map;
CREATE TEMPORARY TABLE tmp_real_category_map AS
SELECT
    name,
    MIN(id) AS category_id
FROM categories
GROUP BY name;

SET @deduped_real_games = (SELECT COUNT(*) FROM tmp_real_games);
SET @missing_primary_category = (
    SELECT COUNT(*)
    FROM tmp_real_games seed
    LEFT JOIN tmp_real_category_map primary_cat
        ON primary_cat.name = seed.primary_category
    WHERE primary_cat.category_id IS NULL
);
SET @existing_real_games = (
    SELECT COUNT(*)
    FROM tmp_real_games seed
    JOIN games existing
        ON TRIM(existing.name) = TRIM(seed.game_name)
);

-- 插入游戏数据
INSERT INTO games (
    name,
    description,
    category_id,
    developer,
    publisher,
    release_date,
    price,
    discount_price,
    image_url,
    system_requirements,
    tags,
    rating,
    rating_count,
    download_count,
    is_featured,
    status
)
SELECT
    seed.game_name,
    seed.description,
    primary_cat.category_id,
    seed.developer,
    seed.publisher,
    seed.release_date,
    seed.price,
    seed.discount_price,
    seed.image_url,
    seed.requirements,
    seed.tags,
    seed.rating,
    seed.rating_count,
    seed.download_count,
    seed.is_featured,
    'ACTIVE'
FROM tmp_real_games seed
JOIN tmp_real_category_map primary_cat
    ON primary_cat.name = seed.primary_category
LEFT JOIN games existing
    ON TRIM(existing.name) = TRIM(seed.game_name)
WHERE existing.id IS NULL;

SET @inserted_real_games = ROW_COUNT();

-- =========================================================
-- 插入game_categories关联表（主分类）
-- =========================================================
INSERT INTO game_categories (game_id, category_id)
SELECT game_ref.id, category_ref.category_id
FROM tmp_real_games mapping
JOIN games game_ref
    ON TRIM(game_ref.name) = TRIM(mapping.game_name)
JOIN tmp_real_category_map category_ref
    ON category_ref.name = mapping.primary_category
LEFT JOIN game_categories gc
    ON gc.game_id = game_ref.id AND gc.category_id = category_ref.category_id
WHERE gc.game_id IS NULL;

-- =========================================================
-- 插入game_categories关联表（次分类）
-- =========================================================
INSERT INTO game_categories (game_id, category_id)
SELECT game_ref.id, category_ref.category_id
FROM tmp_real_games mapping
JOIN games game_ref
    ON TRIM(game_ref.name) = TRIM(mapping.game_name)
JOIN tmp_real_category_map category_ref
    ON category_ref.name = mapping.secondary_category
LEFT JOIN game_categories gc
    ON gc.game_id = game_ref.id AND gc.category_id = category_ref.category_id
WHERE gc.game_id IS NULL;

-- =========================================================
-- 插入game_categories关联表（第三分类，不为空时）
-- =========================================================
INSERT INTO game_categories (game_id, category_id)
SELECT game_ref.id, category_ref.category_id
FROM tmp_real_games mapping
JOIN games game_ref
    ON TRIM(game_ref.name) = TRIM(mapping.game_name)
JOIN tmp_real_category_map category_ref
    ON category_ref.name = mapping.tertiary_category
LEFT JOIN game_categories gc
    ON gc.game_id = game_ref.id AND gc.category_id = category_ref.category_id
WHERE mapping.tertiary_category IS NOT NULL
  AND gc.game_id IS NULL;

-- =========================================================
-- 清理临时表
-- =========================================================
DROP TEMPORARY TABLE IF EXISTS tmp_real_category_map;
DROP TEMPORARY TABLE IF EXISTS tmp_real_games;

-- =========================================================
-- 完成提示
-- =========================================================
SELECT CONCAT(
    '去重后共', @deduped_real_games, '条，成功插入', @inserted_real_games,
    '条，已存在跳过', @existing_real_games, '条，缺少主分类跳过', @missing_primary_category, '条'
) AS result;
